#!/usr/bin/env python3
# Vendor Suit -- "Generate invoice" piece (i): dream-os routine + pwa /pdf trigger.
# Adds generateInvoiceForBinder (idempotent: number + PDF, reuses createInvoice +
# generateAndStoreInvoicePdf, linked by binder_id) and re-points GET /:id/pdf to it.
# NO engine touch. REQUIRES the binder_id column migration applied first.
#   unzip -o vendor-suit-geninvoice-i-pwa-v1.zip && python3 writer.py
import os, sys, base64, json
ROOT = os.getcwd()
def die(m): print("ABORT: " + m); sys.exit(1)
if not os.path.isfile("package.json") or json.load(open("package.json")).get("name") != "dream-os-backend":
    die("run from the dream-os repo root.")
F = os.path.join(ROOT, "src", "api", "vendor", "invoices.js")
P = {'old_pdf': '', 'new_pdf': '', 'routine': ''}
dec = lambda k: base64.b64decode(P[k]).decode()
txt = open(F, encoding="utf-8").read()

if "generateInvoiceForBinder" in txt:
    print("= already applied (idempotent)."); sys.exit(0)

# 1 — insert the routine right after generateAndStoreInvoicePdf's closing brace.
#     anchor = the line that starts the OLD pdf handler; insert routine before it.
anchor = "router.get('/:invoiceId/pdf'"
if anchor not in txt: die("/pdf handler anchor not found -- inspect.")
txt = txt.replace(anchor, dec("routine").lstrip("\n") + "\n\n" + anchor, 1)
print("+ added generateInvoiceForBinder routine")

# 2 — swap the /pdf handler body
old, new = dec("old_pdf"), dec("new_pdf")
if old not in txt: die("old /pdf handler not found verbatim -- inspect.")
txt = txt.replace(old, new, 1)
print("+ re-pointed GET /:id/pdf -> generate-or-serve from binder")

open(F, "w", encoding="utf-8").write(txt)
print("\nDone. Run the binder_id migration FIRST, then restart.")
